private IEnumerable<Symbol> SelectAssets(IEnumerable<EODHDUpcomingEarnings> earnings)
{
    return from d in earnings
           where d.ReportDate <= Time.AddDays(3) && d.Estimate > 0m
           select d.Symbol;
}

private static readonly List<DealType> _dealTypesWanted = new() { DealType.Expected, DealType.Priced };

private IEnumerable<Symbol> SelectAssets(IEnumerable<EODHDUpcomingIPOs> ipos)
{
    // confirmed non-penny stock IPO that launches within 7 days.
    return from d in ipos
           where _dealTypesWanted.Contains(d.DealType)
                && d.IpoDate.HasValue
                && new[] { d.LowestPrice, d.HighestPrice, d.OfferPrice }.Where(x => x.HasValue).Min().Value > 1m
           select d.Symbol;
}

