private IEnumerable<Symbol> SelectAssets(IEnumerable<BaseData> altCoarse)
{
    var cnbcDataBySymbol = new Dictionary<Symbol, List<QuiverCNBCsUniverse>>();
    foreach (var datum in altCoarse.OfType<QuiverCNBCsUniverse>())
    {
        if (!cnbcDataBySymbol.ContainsKey(datum.Symbol))
        {
            cnbcDataBySymbol[datum.Symbol] = new List<QuiverCNBCsUniverse>();
        }
        cnbcDataBySymbol[datum.Symbol].Add(datum);
    }
    return from kvp in cnbcDataBySymbol
           where kvp.Value.Count(x => x.Direction == OrderDirection.Buy) >= 3
           select kvp.Key;
}

